"use client";
import * as React from "react";
import { breadcrumbAnatomy } from "@tessera/core";

export interface BreadcrumbItem {
  label: string;
  href?: string;
}

export interface BreadcrumbProps extends React.HTMLAttributes<HTMLElement> {
  /** Ordered trail; the last item is the current page (aria-current). */
  items: BreadcrumbItem[];
  separator?: React.ReactNode;
}

export const Breadcrumb = React.forwardRef<HTMLElement, BreadcrumbProps>(function Breadcrumb(
  { items, separator = "/", ...rest },
  ref
) {
  return (
    <nav {...breadcrumbAnatomy.attrs("root")} aria-label="Breadcrumb" ref={ref} {...rest}>
      <ol {...breadcrumbAnatomy.attrs("list")}>
        {items.map((item, index) => {
          const isCurrent = index === items.length - 1;
          return (
            <li key={`${item.label}-${index}`} {...breadcrumbAnatomy.attrs("item")}>
              <a
                {...breadcrumbAnatomy.attrs("link")}
                href={isCurrent ? undefined : item.href}
                aria-current={isCurrent ? "page" : undefined}
              >
                {item.label}
              </a>
              {!isCurrent && (
                <span {...breadcrumbAnatomy.attrs("separator")} aria-hidden>
                  {separator}
                </span>
              )}
            </li>
          );
        })}
      </ol>
    </nav>
  );
});

@layer tessera.recipes {
  [data-scope="breadcrumb"][data-part="list"] {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: var(--ts-space-1);
    margin: 0;
    padding: 0;
    list-style: none;
    font-size: var(--ts-font-size-sm);
  }

  [data-scope="breadcrumb"][data-part="item"] {
    display: inline-flex;
    align-items: center;
    gap: var(--ts-space-1);
  }

  [data-scope="breadcrumb"][data-part="link"] {
    color: var(--ts-fg-muted);
    text-decoration: none;
    border-radius: var(--ts-radius-sm);
    padding: 2px var(--ts-space-1);
  }

  [data-scope="breadcrumb"][data-part="link"]:hover {
    color: var(--ts-fg-default);
    text-decoration: underline;
  }

  [data-scope="breadcrumb"][data-part="link"][aria-current="page"] {
    color: var(--ts-fg-default);
    font-weight: var(--ts-font-weight-medium);
    text-decoration: none;
    cursor: default;
  }

  [data-scope="breadcrumb"][data-part="separator"] {
    display: inline-flex;
    color: var(--ts-fg-subtle);
    user-select: none;
  }
}
